export class ComprasComponent {
  constructor(compraService, proveedorService, productoService) {
    this.compraService = compraService;
    this.proveedorService = proveedorService;
    this.productoService = productoService;
    this.compras = [];
    this.proveedores = [];
    this.productos = [];
    this.mostrarFormulario = false;
    this.compraActual = this.nuevaCompra();
    this.productoTemp = null;
    this.cantidadTemp = 1;
    this.precioTemp = 0;
  }
  ngOnInit() {
    this.cargarCompras();
    this.cargarProveedores();
    this.cargarProductos();
  }
  cargarCompras() {
    this.compraService.obtenerTodas().subscribe({
      next: data => this.compras = data,
      error: err => console.error('Error al cargar compras:', err)
    });
  }
  cargarProveedores() {
    this.proveedorService.obtenerActivos().subscribe({
      next: data => this.proveedores = data,
      error: err => console.error('Error al cargar proveedores:', err)
    });
  }
  cargarProductos() {
    this.productoService.obtenerActivos().subscribe({
      next: data => this.productos = data,
      error: err => console.error('Error al cargar productos:', err)
    });
  }
